//--------------------------------------------------------------------
// 하역 실적 물량 그리드 엑셀 
//--------------------------------------------------------------------
scwin.runExcel1 = function () {

    let options = {
        fileName: "하역실적물량조회.xlsx",
        sheetName: "하역실적물량조회"
    }

    let grdObj = gr_StevedoringVolumeResults;

    let infoArr = {};

    if (ds_StevedoringVolumeResults.getTotalRow() == 0) {
        return;
    } else {
        $c.data.downloadGridViewExcel(grdObj, options, infoArr)
    }

}


